prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?midNorm ?midOrig WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?midNorm . }
  OPTIONAL { ?model tai:originalId ?midOrig . }
  FILTER( 
    (?midNorm = "1c273a0818b146269ac04f6b8d518698") || 
    (?midOrig = "1c273a0818b146269ac04f6b8d518698") || 
    (CONTAINS(LCASE(STR(?modelName)), LCASE("1c273a0818b146269ac04f6b8d518698")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1c273a0818b146269ac04f6b8d518698" .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo .
  }

  # Fallback: some models may not use bboExt:ChoreographyTask typing consistently
  OPTIONAL {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_sourceRef ?task .
    ?edge bbo:has_targetRef ?t2 .
    FILTER(?task != ?t2)
  }
}
GROUP BY ?model
